@@ -7076,6 +7076,81 @@ static bool simplifySwitchOfPowersOfTwo(SwitchInst *SI, IRBuilder<> &Builder,

   return true;
 }
+/// When the condition to a switch is the result of a urem with constant
+/// divisor, all possible values are covered by the range [0, divisor-1].
+/// For any values in this range that are not explicitly covered by switch cases,
+/// add explicit cases going to the default destination and make the default
+/// unreachable. This helps expose optimization opportunities.
+/// For example:
+///   %r = urem i64 %x, 4
+///   switch i64 %r, label %default [
+///     i64 1, label %a
+///     i64 2, label %a
+///     i64 3, label %b
+///   ]
+/// becomes:
+///   %r = urem i64 %x, 4
+///   switch i64 %r, label %unreachable [
+///     i64 0, label %default
+///     i64 1, label %a
+///     i64 2, label %a
+///     i64 3, label %b
+///   ]
+static bool simplifySwitchOnURem(SwitchInst *SI, DomTreeUpdater *DTU,
+                                  const DataLayout &DL) {
+  Value *Cond = SI->getCondition();
+  Value *URemOp;
+  const APInt *Divisor;
+  if (!match(Cond, m_URem(m_Value(URemOp), m_APInt(Divisor)))) {
+    // DEBUG: Log match failure
+    LLVM_DEBUG(dbgs() << "SimplifyCFG: simplifySwitchOnURem: match failed. Cond: " << *Cond << "\n");
+    return false;
+  }
+  LLVM_DEBUG(dbgs() << "SimplifyCFG: simplifySwitchOnURem: matched. Divisor: " << *Divisor << "\n");
+
+  // Only handle small divisors to avoid excessive case explosion.
+  // The max value should fit in 64 bits for simplicity.
+  if (Divisor->getBitWidth() > 64 || Divisor->isZero() ||
+      Divisor->getZExtValue() > 64)
+    return false;
+
+  uint64_t DivisorVal = Divisor->getZExtValue();
+
+  // Skip if default is already unreachable.
+  if (isa<UnreachableInst>(SI->getDefaultDest()->getFirstNonPHIOrDbg()))
+    return false;
+
+  // Gather existing case values as a bitset. The divisor tells us the range
+  // [0, divisor-1] of possible values from the urem.
+  BitVector Covered(DivisorVal, false);
+  for (const auto &Case : SI->cases()) {
+    uint64_t CaseVal = Case.getCaseValue()->getValue().getZExtValue();
+    if (CaseVal < DivisorVal)
+      Covered.set(CaseVal);
+  }
+
+  // Check if all values in [0, divisor-1] are covered by explicit cases.
+  // If already fully covered, we can just make default unreachable.
+  // Otherwise, we need to add the missing cases.
+  if (!Covered.all()) {
+    // Not all values are covered, so the default will be taken for those.
+    // Add explicit cases for missing values going to the default destination.
+    BasicBlock *DefaultDest = SI->getDefaultDest();
+    IntegerType *CondTy = cast<IntegerType>(Cond->getType());
+
+    // Find missing values and add cases for them.
+    for (unsigned i = 0, e = DivisorVal; i < e; ++i) {
+      if (!Covered.test(i)) {
+        SI->addCase(ConstantInt::get(CondTy, i), DefaultDest);
+      }
+    }
+  }
+
+  // Now all values in [0, divisor-1] are covered by explicit cases,
+  // so the default is unreachable.
+  createUnreachableSwitchDefault(SI, DTU);
+  return true;
+}

 bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
   BasicBlock *BB = SI->getParent();
@@ -7109,6 +7184,10 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
   if (eliminateDeadSwitchCases(SI, DTU, Options.AC, DL))
     return requestResimplify();

+  // Add missing cases for switch on urem and make default unreachable.
+  if (simplifySwitchOnURem(SI, DTU, DL))
+    return requestResimplify();
+
   if (trySwitchToSelect(SI, Builder, DTU, DL, TTI))
     return requestResimplify();

